count = 0
for root_dir, dirs, files in os.walk('resources/views'):
    for file in files:
        if file.endswith('.blade.php'):
            filepath = os.path.join(root_dir, file)
            with open(filepath, 'r', encoding='utf-8') as f:
                content = f.read()
            
            modified = False
            for emoji, svg in replacements.items():
                if emoji in content:
                    content = content.replace(emoji, svg)
                    modified = True
            
            if modified:
                with open(filepath, 'w', encoding='utf-8') as f:
                    f.write(content)
                count += 1

print(f"Berhasil mengganti emoji di {count} file.")
